// Solo prepara datos de ubicación. El throttle real va en Postgres (multi-worker).
// Telegram seguirá creando 1 ejecución por webhook; eso no se puede desactivar.
// Tras "Throttle DB": 0 filas = dentro del minuto (no conectes nada más o usa IF).

const root = $json;
const msg = root.message || root.edited_message;
if (!msg) {
  return [];
}
if (!msg.location || msg.location.latitude === undefined || msg.location.longitude === undefined) {
  return [];
}

return [{
  json: {
    chat_id: msg.chat.id,
    user_id: msg.from.id,
    user_name: String(msg.from.first_name || 'Usuario'),
    latitude: msg.location.latitude,
    longitude: msg.location.longitude,
    horizontal_accuracy: msg.location.horizontal_accuracy ?? null,
    live_period: msg.location.live_period ?? null,
    message_id: msg.message_id,
    message_date_unix: msg.date ?? null,
    es_edited_message: !!root.edited_message
  }
}];

